export function getVerbVocabulary(): VocabWord[] {
  return VERB_DATA.map(e => ({
    id: e.id,
    russian: e.russian,
    german: e.german,
    transliteration: e.transliteration,
    example: e.example_ru ? e.example_ru + ' — ' + e.example_de : undefined,
    tags: ['verb', e.aspekt, e.form],
    mastery: 'new' as const,
    correctCount: 0,
    incorrectCount: 0,
  }));
}

export function getVerbIds(): Set<string> {
  return new Set(VERB_DATA.map(e => e.id));
}
